/** Get field requirements for a category + marketplace */
export function getCategoryFields(
  category: string,
  marketplace: 'ebay' | 'vinted'
): CategoryFieldDef[] {
  return CATEGORY_FIELD_REQUIREMENTS[category]?.[marketplace] ?? []
}

/** Get only required fields for a category + marketplace */
export function getRequiredFields(
  category: string,
  marketplace: 'ebay' | 'vinted'
): CategoryFieldDef[] {
  return getCategoryFields(category, marketplace).filter(f => f.required)
}

